=<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Confirm Outreach</title>
  <style>
    body {
      margin: 0;
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background: #f4f7fb;
      color: #1f2937;
      display: flex;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
    }
    .card {
      max-width: 560px;
      margin: 24px;
      background: #ffffff;
      border-radius: 16px;
      padding: 40px 32px;
      box-shadow: 0 12px 40px rgba(0, 0, 0, 0.08);
      text-align: center;
      border: 1px solid #e5e7eb;
    }
    h1 {
      margin: 0 0 16px;
      font-size: 26px;
      line-height: 1.2;
      color: #111827;
    }
    p {
      margin: 0 0 20px;
      font-size: 17px;
      line-height: 1.6;
      color: #4b5563;
    }
    .ref {
      font-family: monospace;
      background: #f3f4f6;
      padding: 2px 8px;
      border-radius: 4px;
      font-size: 14px;
      word-break: break-all;
    }
    button {
      background: #2563eb;
      color: #ffffff;
      border: none;
      border-radius: 10px;
      padding: 14px 36px;
      font-size: 18px;
      font-weight: 600;
      cursor: pointer;
      transition: background 0.2s;
    }
    button:hover {
      background: #1d4ed8;
    }
    button:disabled {
      background: #9ca3af;
      cursor: not-allowed;
    }
    .subtle {
      margin-top: 18px;
      font-size: 14px;
      color: #9ca3af;
    }
    .tick {
      font-size: 42px;
      line-height: 1;
      margin-bottom: 18px;
    }
    .hidden { display: none; }
    .error { color: #dc2626; }
  </style>
</head>
<body>
  <div class="card" id="confirmCard">
    <h1>Confirm outreach campaign</h1>
    <p>You are about to queue lead:<br><span class="ref">{{ $json.query.jobRef }}</span></p>
    <button id="btn" onclick="queueLead()">Queue this lead</button>
    <p class="subtle">Only pressing the button above will queue the lead.</p>
  </div>

  <div class="card hidden" id="successCard">
    <div class="tick">&#10003;</div>
    <h1>Your outreach campaign will appear in Teams shortly</h1>
    <p>You can now close this tab.</p>
    <p class="subtle">Your request has been received and added to the queue.</p>
  </div>

  <div class="card hidden" id="errorCard">
    <h1 class="error">Something went wrong</h1>
    <p id="errorMsg"></p>
    <button onclick="location.reload()">Try again</button>
  </div>

  <script>
    function showError(message) {
      document.getElementById('confirmCard').classList.add('hidden');
      document.getElementById('successCard').classList.add('hidden');
      document.getElementById('errorCard').classList.remove('hidden');
      document.getElementById('errorMsg').innerText = message || 'Unknown error';
    }

    function showSuccess() {
      document.getElementById('confirmCard').classList.add('hidden');
      document.getElementById('errorCard').classList.add('hidden');
      document.getElementById('successCard').classList.remove('hidden');
    }

    function queueLead() {
      var btn = document.getElementById('btn');
      btn.disabled = true;
      btn.innerText = 'Queuing...';

      fetch('https://antonyberou.app.n8n.cloud/webhook/job-lead-queue-confirm', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          jobRef: '{{ $json.query.jobRef }}',
          userKey: '{{ $json.query.userKey }}'
        })
      })
      .then(function(r) {
        if (!r.ok) {
          throw new Error('Queue request failed with status ' + r.status);
        }
        return r.json().catch(function() { return {}; });
      })
      .then(function() {
        fetch('https://antonyberou.app.n8n.cloud/webhook/job-queue-drain', {
          method: 'GET',
          mode: 'no-cors'
        }).catch(function() {});

        showSuccess();
      })
      .catch(function(e) {
        showError(e.message);
      });
    }
  </script>
</body>
</html>
